const msg = $input.first().json;

if (msg.html || msg.text) {
  return [{ json: { html_body: msg.html || msg.text } }];
}

function findPart(parts, mimeType) {
  if (!Array.isArray(parts)) return null;
  for (const p of parts) {
    if (p.mimeType === mimeType && p.body?.data) return p.body.data;
    if (p.parts) {
      const found = findPart(p.parts, mimeType);
      if (found) return found;
    }
  }
  return null;
}

const parts = msg.payload?.parts || [];
const b64 = findPart(parts, 'text/html') || findPart(parts, 'text/plain') || '';
const html_body = b64
  ? Buffer.from(b64.replace(/-/g, '+').replace(/_/g, '/'), 'base64').toString('utf-8')
  : msg.snippet || '';

return [{ json: { html_body } }];

const trigger = $('Gmail Trigger').first().json;
const from = trigger.From || '';
const match = from.match(/<([^>]+)>/) || from.match(/([^\s]+@[^\s]+)/);
const fromEmail = (match ? match[1] : from).toLowerCase().trim();

const agents = {
  'eknutson@teamyellownow.com': {
    client_id: 'ded234e3-1c78-45c3-8924-6036e1fcaf60',
    agent_email: 'eknutson@teamyellownow.com'
  },
  'mjasinski@teamyellownow.com': {
    client_id: '451306d1-6437-42b8-8ffe-c16f28803490',
    agent_email: 'mjasinski@teamyellownow.com'
  },
  'hello@norrai.co': {
    client_id: '94f4a987-c64c-4252-989c-41af296e732f',
    agent_email: 'hello@norrai.co'
  }
};

const agent = agents[fromEmail];
if (!agent) {
  throw new Error(`Unrecognized forwarding address: ${fromEmail}`);
}

return [{
  json: {
    client_id: agent.client_id,
    agent_email: agent.agent_email,
    html_body: $('Decode Email Body').first().json.html_body || '',
    subject: trigger.Subject || '',
    from_raw: from
  }
}];

const d = $('Resolve Agent').first().json;
return [{
  json: {
    html_body: d.html_body,
    client_id: d.client_id,
    agent_email: d.agent_email
  }
}];
